import React from "react";
import Link from "next/link";
import type { LegalConfig } from "../types";
import { LegalPageLayout, type LegalSection } from "../components/LegalPageLayout";
import { LegalDisclaimer } from "../components/LegalDisclaimer";

const sections: LegalSection[] = [
  { id: "commitment", label: "Our Commitment" },
  { id: "standard", label: "Accessibility Standard & Target" },
  { id: "measures", label: "Measures We Take" },
  { id: "compatibility", label: "Browser & Assistive Tech Compatibility" },
  { id: "technical", label: "Technical Specifications" },
  { id: "known", label: "Known Limitations" },
  { id: "testing", label: "Testing & Continuous Improvement" },
  { id: "feedback", label: "Feedback & Help" },
  { id: "enforcement", label: "Enforcement Procedure" },
  { id: "date", label: "Statement Date" },
];

const defaultTechnologies = [
  "HTML, WAI-ARIA",
  "CSS (Tailwind CSS)",
  "JavaScript (React/Next.js)",
];

interface AccessibilityPageProps {
  config: LegalConfig;
}

export function AccessibilityPage({ config }: AccessibilityPageProps) {
  const technologies = config.technologies ?? defaultTechnologies;

  return (
    <LegalPageLayout
      eyebrow="Accessibility"
      title="Accessibility Statement"
      subtitle={`${config.company.shortName} is committed to providing a website that is accessible to the widest possible audience, regardless of technology or ability. We are continually improving the user experience and applying relevant accessibility standards.`}
      sections={sections}
    >
      <section id="commitment">
        <h2>Our Commitment</h2>
        <p>
          We aim to make our content and features perceivable, operable, understandable, and robust
          for all users, including people who use assistive technologies such as screen readers,
          screen magnifiers, speech recognition software, and switch devices.
        </p>
      </section>

      <section id="standard">
        <h2>Accessibility Standard &amp; Target</h2>
        <p>
          Our goal is conformance with the Web Content Accessibility Guidelines (WCAG) 2.2 Level AA.
          Where full conformance is not yet possible, we work to provide accessible alternatives and
          prioritize fixes according to user impact.
        </p>
      </section>

      <section id="measures">
        <h2>Measures We Take</h2>
        <ul>
          <li>Use semantic HTML, proper heading structure, and accessible form patterns.</li>
          <li>Maintain sufficient color contrast and clear focus indicators.</li>
          <li>Provide text alternatives for non-text content (e.g., images).</li>
          <li>Ensure keyboard operability and logical tab order.</li>
          <li>Label interactive components and ARIA attributes where required.</li>
          <li>Continuously review new UI against accessibility acceptance criteria.</li>
        </ul>
      </section>

      <section id="compatibility">
        <h2>Browser &amp; Assistive Tech Compatibility</h2>
        <p>
          We test modern versions of major browsers (Chrome, Edge, Safari, Firefox) on desktop and
          mobile. We also spot-check with screen readers (e.g., VoiceOver, NVDA) where feasible.
          While we strive for broad support, older browsers or unusual configurations may not offer a
          fully accessible experience.
        </p>
      </section>

      <section id="technical">
        <h2>Technical Specifications</h2>
        <p>
          Accessibility of {config.company.shortName} relies on the following technologies to
          function with the particular combination of web browser and assistive technologies or
          plugins installed on your device:
        </p>
        <ul>
          {technologies.map((tech) => (
            <li key={tech}>{tech}</li>
          ))}
        </ul>
        <p>
          These technologies are relied upon to conform with the accessibility standards used.
        </p>
      </section>

      <section id="known">
        <h2>Known Limitations</h2>
        <p>
          Despite our best efforts, some content may not yet be fully accessible. Known items we
          monitor:
        </p>
        <ul>
          <li>
            Third-party embeds or iframes may not meet our target standard (we provide titles/labels
            where possible).
          </li>
          <li>
            Legacy media or documents may not have complete transcripts or alternative formats
            (contact us for an accessible copy).
          </li>
          <li>
            User-generated content might not include full text alternatives on upload (we provide
            guidance and review paths).
          </li>
        </ul>
      </section>

      <section id="testing">
        <h2>Testing &amp; Continuous Improvement</h2>
        <p>
          We use a blend of automated checks and manual reviews during development. Accessibility
          feedback is triaged and tracked, and remediations are prioritized by severity and user
          impact.
        </p>
      </section>

      <section id="feedback">
        <h2>Feedback &amp; Help</h2>
        <p>
          If you experience a barrier or need an alternative format, contact us. We try to respond
          within 5 business days.
        </p>
        <ul>
          <li>
            Email:{" "}
            <a href={`mailto:${config.contact.accessibilityEmail}`}>
              {config.contact.accessibilityEmail}
            </a>
          </li>
          {config.contact.phone && <li>Phone: {config.contact.phone}</li>}
          {config.contact.mailingAddress && (
            <li>Postal: {config.contact.mailingAddress}</li>
          )}
        </ul>
        <p>
          When contacting us, please include the page URL, a description of the issue, your
          browser/OS, and any assistive technology in use.
        </p>
        <p className="text-sm text-neutral-500 dark:text-white/70">
          For privacy information, see our <Link href="/privacy">Privacy Policy</Link>. For site use
          rules, see our <Link href="/terms">Terms of Use</Link>.
        </p>
      </section>

      <section id="enforcement">
        <h2>Enforcement Procedure</h2>
        <p>
          If you believe your accessibility complaint has not been satisfactorily resolved, you may
          escalate it to our internal compliance lead at{" "}
          <a href={`mailto:${config.contact.legalEmail}`}>{config.contact.legalEmail}</a>. We will
          review and respond with next steps and timing.
        </p>
      </section>

      <section id="date">
        <h2>Statement Date</h2>
        <p>This statement was last updated on {config.effectiveDate}.</p>
      </section>

      <LegalDisclaimer />
    </LegalPageLayout>
  );
}
